// Extract and validate the inbound request body.
// Vercel API route is responsible for JWT validation; this workflow trusts user_id from body.
const body = $input.first().json.body || {};
const user_id = body.user_id;
const deal_id = body.deal_id;
const message = body.message;
const conversation_id = body.conversation_id || null;

const valid = Boolean(user_id && deal_id && message && typeof message === 'string' && message.trim().length > 0);

return [{
  json: {
    valid,
    user_id,
    deal_id,
    conversation_id,
    message: message ? message.trim() : '',
    error: valid ? null : 'Missing required fields: user_id, deal_id, message',
    start_ts: Date.now()
  }
}];

// Combine deal info from the entitlement check with the original request context.
const deal = $input.first().json;
const orig = $('Extract Request').first().json;
return [{
  json: {
    user_id: orig.user_id,
    deal_id: orig.deal_id,
    conversation_id: orig.conversation_id,
    message: orig.message,
    deal_name: deal.name,
    deal_status: deal.status
  }
}];

// Normalise the conversation row from either branch (existing lookup or newly created).
// `is_new_conversation` is derived from whether the caller sent a conversation_id in the body —
// not from the row's title (Haiku may not have written it yet on a continuing thread).
const row = $input.first().json;
const ctx = $('Carry Context').first().json;

if (!row.id) {
  throw new Error('Failed to obtain conversation row');
}

const isNew = !ctx.conversation_id;

return [{
  json: {
    ...ctx,
    conversation_id: row.id,
    conversation_title: row.title,
    is_new_conversation: isNew
  }
}];

const startTs = Number($('Extract Request').first().json.start_ts ?? Date.now());
const latency_ms = Date.now() - startTs;

const item = $input.first().json;
const output = (item.output ?? '').toString();
const intermediateSteps = Array.isArray(item.intermediateSteps) ? item.intermediateSteps : [];

let input_tokens = 0;
let output_tokens = 0;

// 1. REAL Anthropic usage for tool-decision turns. Lives at
//    intermediateSteps[*].action.messageLog[*].kwargs.usage_metadata.
//    This captures the system prompt + memory + tool definitions input cost.
let lastToolDecisionInput = 0;
for (const step of intermediateSteps) {
  for (const log of step?.action?.messageLog ?? []) {
    const um = log?.kwargs?.usage_metadata;
    if (um) {
      input_tokens  += Number(um.input_tokens  ?? 0);
      output_tokens += Number(um.output_tokens ?? 0);
      lastToolDecisionInput = Number(um.input_tokens ?? 0);
    }
  }
}

// 2. SYNTHESIS turn estimate. The final-answer LLM call has no `action`,
//    so it's not in intermediateSteps; n8n's lmChatAnthropic node also
//    doesn't surface its real usage. Approximate from data we have:
//    - synth input ≈ last tool-decision input (same system+memory) + tool
//      observation sizes (re-sent as tool_result content) / 4.
//    - synth output ≈ final answer char count / 4.
//    Char/4 is the industry approximation; this is directional, not exact.
if (intermediateSteps.length > 0) {
  let observationChars = 0;
  for (const step of intermediateSteps) {
    const obs = step?.observation ?? '';
    observationChars += (typeof obs === 'string' ? obs : JSON.stringify(obs)).length;
  }
  const synthInputEstimate  = lastToolDecisionInput + Math.ceil(observationChars / 4);
  const synthOutputEstimate = Math.ceil(output.length / 4);
  input_tokens  += synthInputEstimate;
  output_tokens += synthOutputEstimate;
}

const model = 'claude-sonnet-4-6';

const tool_calls = intermediateSteps.length > 0
  ? intermediateSteps.map((s) => ({
      tool: s?.action?.tool ?? null,
      input: s?.action?.toolInput ?? null,
      observation_preview: typeof s?.observation === 'string' ? s.observation.slice(0, 500) : null,
    }))
  : null;

const tool_calls_json = tool_calls ? JSON.stringify(tool_calls) : null;

return [{
  json: {
    output,
    latency_ms,
    input_tokens,
    output_tokens,
    model,
    tool_calls,
    tool_calls_json,
  }
}];

